import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Horde Magic 2.0: Introducing The Raid","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/sources/horde-raid-quiet-speculation.md","filePath":"formats/horde/sources/horde-raid-quiet-speculation.md","lastUpdated":1782025909000}'),o={name:"formats/horde/sources/horde-raid-quiet-speculation.md"};function s(l,e,n,d,h,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="horde-magic-2-0-introducing-the-raid" tabindex="-1">Horde Magic 2.0: Introducing The Raid <a class="header-anchor" href="#horde-magic-2-0-introducing-the-raid" aria-label="Permalink to &quot;Horde Magic 2.0: Introducing The Raid&quot;">​</a></h1><p>Source: <a href="https://www.quietspeculation.com/2013/02/horde-magic-2-0-introducing-the-raid/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2013/02/horde-magic-2-0-introducing-the-raid/</a></p><p>Author: Peter Knudson<br> Published: February 18, 2013</p><p>This article revisits Horde Magic and proposes <strong>Raid</strong>, a staged variant where the Horde deck becomes more like a roleplaying quest or dungeon.</p><h2 id="premise" tabindex="-1">Premise <a class="header-anchor" href="#premise" aria-label="Permalink to &quot;Premise&quot;">​</a></h2><p>The article frames Horde Magic as a story generator. A good Horde deck should not just be a pile of enemy cards; it should explain what the Survivors are fighting, why the battle matters, and what kind of memorable moments the table is trying to create.</p><p>Raid pushes this further by letting the Horde designer act a bit like a dungeon master.</p><h2 id="raid-rules" tabindex="-1">Raid Rules <a class="header-anchor" href="#raid-rules" aria-label="Permalink to &quot;Raid Rules&quot;">​</a></h2><p>Raid uses normal Horde Magic as its base, with three major changes:</p><ol><li>The Horde deck is semi-ordered before play.</li><li>Cards inside each quest or stage are randomized, but the stages occur in a set order.</li><li>Artifacts revealed by the Horde do not count as non-token cards; they become loot for the Survivors.</li><li>Survivors cannot attack the Horde deck directly.</li></ol><p>Because Survivors cannot mill the Horde by attacking, Raid is more defensive and scenario-driven.</p><h2 id="why-semi-order-the-deck" tabindex="-1">Why Semi-Order The Deck? <a class="header-anchor" href="#why-semi-order-the-deck" aria-label="Permalink to &quot;Why Semi-Order The Deck?&quot;">​</a></h2><p>The deck order lets the scenario tell a story. Survivors can fight through one stage, then another, then a boss or finale.</p><p>Within each stage, the cards can still be randomized so the game does not play out exactly the same way every time.</p><h2 id="example-the-dragonborn" tabindex="-1">Example: The Dragonborn <a class="header-anchor" href="#example-the-dragonborn" aria-label="Permalink to &quot;Example: The Dragonborn&quot;">​</a></h2><p>The article&#39;s first Raid example is inspired by Skyrim. The Survivors fight through wilderness creatures, soldiers, vampires, undead, dragons, and a final boss.</p><h3 id="stage-order" tabindex="-1">Stage Order <a class="header-anchor" href="#stage-order" aria-label="Permalink to &quot;Stage Order&quot;">​</a></h3><ol><li>Green cards and tokens.</li><li>First Dragon Boss.</li><li>White cards and tokens.</li><li>Second Dragon Boss.</li><li>Black cards and tokens.</li><li>Red cards and Zombie tokens.</li><li>Final Boss.</li></ol><h3 id="story-shape" tabindex="-1">Story Shape <a class="header-anchor" href="#story-shape" aria-label="Permalink to &quot;Story Shape&quot;">​</a></h3><p>The Survivors are trapped in hostile wilderness, then move through escalating conflicts before confronting a world-ending dragon threat.</p><p>The author notes that this list may favor the Survivors and suggests possible fixes such as adding a reset rule after each stage or adding more sweepers.</p><h2 id="example-rat-horde" tabindex="-1">Example: Rat Horde <a class="header-anchor" href="#example-rat-horde" aria-label="Permalink to &quot;Example: Rat Horde&quot;">​</a></h2><p>The second example uses Gatecrash-era Rat support.</p><p>The setup is a city overrun by rats and a criminal syndicate. Survivors must exterminate the infestation before disease overtakes the city.</p><h3 id="rat-horde-design-notes" tabindex="-1">Rat Horde Design Notes <a class="header-anchor" href="#rat-horde-design-notes" aria-label="Permalink to &quot;Rat Horde Design Notes&quot;">​</a></h3><ul><li>Rat tokens are small, so the deck uses anthem-like effects to scale over time.</li><li>Poison counters act as a doom clock.</li><li>If ten poison counters are revealed, the Survivors lose.</li><li>Sorin emblems are used like token flips: they continue the reveal chain and permanently buff the rats.</li><li>Bad Moon appears as an additional scaling hedge.</li></ul><h2 id="other-horde-deck-ideas" tabindex="-1">Other Horde Deck Ideas <a class="header-anchor" href="#other-horde-deck-ideas" aria-label="Permalink to &quot;Other Horde Deck Ideas&quot;">​</a></h2><p>The article closes with more thematic Horde prompts:</p><ul><li>Eldrazi</li><li>Elementals</li><li>Angels</li><li>Demons</li><li>Dragons</li><li>Assassins</li><li>Pirates</li><li>Rebels</li><li>Soldiers</li><li>Saprolings</li><li>Goblins</li><li>Spirits</li><li>Beasts</li><li>Dinosaurs</li></ul><h2 id="takeaways-for-game-night-boxes" tabindex="-1">Takeaways For Game-Night Boxes <a class="header-anchor" href="#takeaways-for-game-night-boxes" aria-label="Permalink to &quot;Takeaways For Game-Night Boxes&quot;">​</a></h2><p>Raid is especially relevant to boxed game nights because it supports scenario packaging:</p><ul><li>A staged enemy deck.</li><li>Boss cards or boss packets.</li><li>Loot cards.</li><li>Scenario sheets.</li><li>Difficulty adjustments between stages.</li><li>A campaign structure where the table fights multiple Raids in sequence.</li></ul><p>Raid also makes Horde more self-contained. If the box includes Survivor decks, the host can tune both sides into a fixed cooperative experience.</p>',33)])])}const m=a(o,[["render",s]]);export{p as __pageData,m as default};
